from llama_index.core.node_parser import HierarchicalNodeParser

parser = HierarchicalNodeParser.from_defaults(
    chunk_sizes=[2048, 512, 128],  # Parent → child hierarchy
)

nodes = parser.get_nodes_from_documents(documents)

# Nodes carry parent-child relationships
for node in nodes:
    if node.metadata.get("level") == "child":
        parent_id = node.relationships.get("parent")
        # Retrievers can load parent for additional context

from llama_index.core.extractors import (
    TitleExtractor, QuestionsAnsweredExtractor,
    SummaryExtractor, KeywordExtractor,
)
from llama_index.core.ingestion import IngestionPipeline

pipeline = IngestionPipeline(
    transformations=[
        SentenceSplitter(chunk_size=512, chunk_overlap=50),
        TitleExtractor(nodes=5),
        QuestionsAnsweredExtractor(questions=3),
        SummaryExtractor(summaries=["self"]),
        KeywordExtractor(keywords=5),
    ]
)

nodes = pipeline.run(documents=documents)

# Nodes now have .metadata["title"], .metadata["keywords"], etc.
for node in nodes:
    print(node.metadata)  # {'title': '...', 'keywords': [...], ...}

# Subagent 1: Ingest
def ingest_agent(input_dir: str, output_dir: str):
    from llama_index.core import (
        VectorStoreIndex, SimpleDirectoryReader, StorageContext
    )
    docs = SimpleDirectoryReader(input_dir).load_data()
    index = VectorStoreIndex.from_documents(docs)
    index.storage_context.persist(output_dir)
    return {"storage_path": output_dir, "node_count": len(index.docstore.docs)}

# Subagent 2: Query
def query_agent(storage_path: str, query: str):
    from llama_index.core import load_index_from_storage, StorageContext
    storage_context = StorageContext.from_defaults(persist_dir=storage_path)
    index = load_index_from_storage(storage_context)
    qe = index.as_query_engine()
    response = qe.query(query)
    return {
        "answer": str(response),
        "sources": [{"text": n.text[:100], "score": n.score} for n in response.source_nodes]
    }

def query_agent_with_confidence(storage_path: str, query: str, min_confidence: float = 0.7):
    storage_context = StorageContext.from_defaults(persist_dir=storage_path)
    index = load_index_from_storage(storage_context)
    qe = index.as_query_engine(node_postprocessors=[SimilarityPostprocessor(similarity_cutoff=min_confidence)])
    response = qe.query(query)

    if not response.source_nodes or response.source_nodes[0].score < min_confidence:
        return {"confidence": "low", "answer": "I don't have sufficient context to answer this question."}

    return {
        "confidence": "high",
        "answer": str(response),
        "sources": [{"text": n.text[:100], "score": n.score} for n in response.source_nodes]
    }
